import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        X = int(next(it))
        cnt = 0
        for _ in range(N):
            age = int(next(it))
            if age >= X:
                cnt += 1
        out_lines.append(str(cnt))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

